import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { CssBaseline } from "@mui/material";
import { AuthProvider, useAuth } from "./context/AuthContext";

// Import all page components
import Login from "./components/Login";
import Navbar from "./components/Navbar";
import Dashboard from "./components/Dashboard";
import Purchases from "./components/Purchases";
import Transfers from "./components/Transfers";
import Assignments from "./components/Assignments";

// ProtectedRoute - wraps pages that require login
// If not logged in → redirect to /login
// If logged in but wrong role → redirect to /
function ProtectedRoute(props) {
  var { user } = useAuth();

  // Not logged in
  if (!user) {
    return <Navigate to="/login" />;
  }

  // Check if user has the required role (if specified)
  if (props.allowedRoles) {
    var hasRole = props.allowedRoles.indexOf(user.role) !== -1;
    if (!hasRole) {
      return <Navigate to="/" />;
    }
  }

  // User is logged in and has the right role - show the page
  return (
    <div>
      <Navbar />
      <div>{props.children}</div>
    </div>
  );
}

// AppRoutes - defines all the pages
function AppRoutes() {
  var { user } = useAuth();

  return (
    <Routes>
      {/* Login page - if already logged in, go to dashboard */}
      <Route
        path="/login"
        element={user ? <Navigate to="/" /> : <Login />}
      />

      {/* Dashboard - all logged in users can see */}
      <Route
        path="/"
        element={
          <ProtectedRoute>
            <Dashboard />
          </ProtectedRoute>
        }
      />

      {/* Purchases - Admin and Logistics Officer only */}
      <Route
        path="/purchases"
        element={
          <ProtectedRoute allowedRoles={["Admin", "Logistics Officer"]}>
            <Purchases />
          </ProtectedRoute>
        }
      />

      {/* Transfers - Admin and Logistics Officer only */}
      <Route
        path="/transfers"
        element={
          <ProtectedRoute allowedRoles={["Admin", "Logistics Officer"]}>
            <Transfers />
          </ProtectedRoute>
        }
      />

      {/* Assignments - Admin and Base Commander only */}
      <Route
        path="/assignments"
        element={
          <ProtectedRoute allowedRoles={["Admin", "Base Commander"]}>
            <Assignments />
          </ProtectedRoute>
        }
      />

      {/* Any unknown URL → go to dashboard */}
      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

// Main App component
function App() {
  return (
    <AuthProvider>
      <CssBaseline />
      <BrowserRouter>
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;
